const LoadingScreen = () => {
  React.useEffect(() => {
    const timer = setTimeout(() => {
      const loadingEl = document.getElementById('loading')
      if (loadingEl) {
        loadingEl.style.opacity = '0'
        loadingEl.style.transition = 'opacity 0.5s ease'
        setTimeout(() => {
          loadingEl.style.display = 'none'
        }, 500)
      }
    }, 1000)

    return () => clearTimeout(timer)
  }, [])

  return null
}

